39	function resolveTarget(to: string, opts?: SendIrcOptions): string {
40	  const fromArg = normalizeIrcMessagingTarget(to);
41	  if (fromArg) {
42	    return fromArg;
43	  }
44	  const fromOpt = normalizeIrcMessagingTarget(opts?.target ?? "");
45	  if (fromOpt) {
46	    return fromOpt;
47	  }
48	  throw new Error(`Invalid IRC target: ${to}`);
49	}
