    approveHint: "This user is not on your allowlist..."
  }
}
```

#### **D. Pairing (DM Approval Flow):**
```typescript
pairing: {
  text: {
    idLabel: "Acme Chat username",
    message: "Send this code to verify your identity:",
    notify: async ({ target, code }) => {
      await acmeChatApi.sendDm(target, `Pairing code: ${code}`);
    }
  }
}
```

#### **E. Reply Threading Modes:**
```typescript
threading: {
  topLevelReplyToMode: "reply" // or use resolveReplyToMode function
}
```

The three modes are:
- **"off"**: No replies, flat messages
- **"first"**: Reply only to original message
- **"all"**: Reply to any message in thread

---

### **8. MANIFEST VALIDATION**

**Key Rules:**

1. **Unknown `channels.*` keys** → Error unless plugin declares them
2. **Unknown plugin ids in `plugins.entries.<id>`** → Error
3. **Missing/broken manifest** → Plugin error (blocks all config validation)
4. **Disabled plugin with existing config** → Warning in Doctor + logs
5. **JSON Schema is required** → Even if empty: `{ "type": "object", "additionalProperties": false }`

---

### **9. FILE STRUCTURE EXAMPLE**

```
my-plugin-root/
├── package.json                    # openclaw.channel metadata
├── openclaw.plugin.json            # Manifest with config schema
├── index.ts                        # defineChannelPluginEntry
├── setup-entry.ts                  # defineSetupPluginEntry
├── api.ts                          # Public exports (optional)
├── runtime-api.ts                  # Internal runtime exports (optional)
└── src/
    ├── channel.ts                  # ChannelPlugin via createChatChannelPlugin
    ├── channel.test.ts             # Tests
    ├── client.ts                   # Platform API client
    ├── inbound.ts                  # Webhook handling
    └── runtime.ts                  # Runtime store (if needed)
```

---

### **10. ENTRY POINT HELPERS**

**Location:** `/src/plugin-sdk/core.ts`, `/src/plugin-sdk/plugin-entry.ts`

```typescript
// For channel plugins
export function defineChannelPluginEntry<TPlugin>(options: {
  id: string;
  name: string;
  description: string;
  plugin: TPlugin;
  configSchema?: OpenClawPluginConfigSchema | (() => OpenClawPluginConfigSchema);
  setRuntime?: (runtime: PluginRuntime) => void;
  registerCliMetadata?: (api: OpenClawPluginApi) => void;
  registerFull?: (api: OpenClawPluginApi) => void;
}): DefinedChannelPluginEntry<TPlugin>;

// For setup-only entry
export function defineSetupPluginEntry<TPlugin>(plugin: TPlugin): { plugin: TPlugin };
```

---

This comprehensive contract system enables OpenClaw to:
- Validate plugin configs **before executing plugin code**
- Route messages through a unified `message` tool
- Manage DM security, pairing, and threading consistently
- Load plugins in different modes (setup-only vs full runtime)
- Support both bundled and external channel plugins

The key design principle is that **core owns shared infrastructure** (message tool, session keys, generic routing) while **plugins own platform specifics** (auth, config, send methods, target resolution, inbound handling).

