91	          messageId: makeIrcMessageId(),
92	          target: inboundTarget.target,
93	          rawTarget: inboundTarget.rawTarget,
94	          senderNick: event.senderNick,
95	          senderUser: event.senderUser,
96	          senderHost: event.senderHost,
97	          text: event.text,
98	          timestamp: Date.now(),
99	          isGroup: inboundTarget.isGroup,
100	        };
101	
102	        core.channel.activity.record({
103	          channel: "irc",
104	          accountId: account.accountId,
105	          direction: "inbound",
106	          at: message.timestamp,
107	        });
108	
109	        if (opts.onMessage) {
110	          await opts.onMessage(message, client);
111	          return;
112	        }
113	
114	        await handleIrcInbound({
115	          message,
116	          account,
117	          config: cfg,
118	          runtime,
119	          connectedNick: client.nick,
120	          sendReply: async (target, text) => {
121	            client?.sendPrivmsg(target, text);
122	            opts.statusSink?.({ lastOutboundAt: Date.now() });
123	            core.channel.activity.record({
124	              channel: "irc",
125	              accountId: account.accountId,
126	              direction: "outbound",
127	            });
128	          },
129	          statusSink: opts.statusSink,
130	        });
131	      },
132	    }),
133	  );
134	
135	  logger.info(
136	    `[${account.accountId}] connected to ${account.host}:${account.port}${account.tls ? " (tls)" : ""} as ${client.nick}`,
137	  );
138	
139	  return {
140	    stop: () => {
141	      client?.quit("shutdown");
142	      client = null;
143	    },
144	  };
145	}
