81	export async function handleIrcInbound(params: {
82	  message: IrcInboundMessage;
83	  account: ResolvedIrcAccount;
84	  config: CoreConfig;
85	  runtime: RuntimeEnv;
86	  connectedNick?: string;
87	  sendReply?: (target: string, text: string, replyToId?: string) => Promise<void>;
88	  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
89	}): Promise<void> {
89	  const { message, account, config, runtime, connectedNick, statusSink } = params;
91	  const core = getIrcRuntime();
92	  const pairing = createChannelPairingController({
93	    core,
94	    channel: CHANNEL_ID,
95	    accountId: account.accountId,
96	  });
97	
98	  const rawBody = message.text?.trim() ?? "";
99	  if (!rawBody) {
100	    return;
101	  }
102	
103	  statusSink?.({ lastInboundAt: message.timestamp });
104	
105	  const senderDisplay = message.senderHost
106	    ? `${message.senderNick}!${message.senderUser ?? "?"}@${message.senderHost}`
107	    : message.senderNick;
108	  const allowNameMatching = isDangerousNameMatchingEnabled(account.config);
109	
110	  const dmPolicy = account.config.dmPolicy ?? "pairing";
111	  const defaultGroupPolicy = resolveDefaultGroupPolicy(config);
112	  const { groupPolicy, providerMissingFallbackApplied } =
113	    resolveAllowlistProviderRuntimeGroupPolicy({
114	      providerConfigPresent: config.channels?.irc !== undefined,
115	      groupPolicy: account.config.groupPolicy,
116	      defaultGroupPolicy,
117	    });
118	  warnMissingProviderGroupPolicyFallbackOnce({
119	    providerKey: "irc",
120	    accountId: account.accountId,
120	    blockedLabel: GROUP_POLICY_BLOCKED_LABEL.channel,
121	    log: (message) => runtime.log?.(message),
122	  });
123	
124	  const configAllowFrom = normalizeIrcAllowlist(account.config.allowFrom);
125	  const configGroupAllowFrom = normalizeIrcAllowlist(account.config.groupAllowFrom);
126	  const storeAllowFrom = await readStoreAllowFromForDmPolicy({
127	    provider: CHANNEL_ID,
128	    accountId: account.accountId,
129	    dmPolicy,
130	    readStore: pairing.readStoreForDmPolicy,
131	  });
132	  const storeAllowList = normalizeIrcAllowlist(storeAllowFrom);
133	
134	  const groupMatch = resolveIrcGroupMatch({
135	    groups: account.config.groups,
136	    target: message.target,
137	  });
138	
139	  if (message.isGroup) {
140	    const groupAccess = resolveIrcGroupAccessGate({ groupPolicy, groupMatch });
141	    if (!groupAccess.allowed) {
142	      runtime.log?.(`irc: drop channel ${message.target} (${groupAccess.reason})`);
143	      return;
144	    }
145	  }
146	
147	  const directGroupAllowFrom = normalizeIrcAllowlist(groupMatch.groupConfig?.allowFrom);
148	  const wildcardGroupAllowFrom = normalizeIrcAllowlist(groupMatch.wildcardConfig?.allowFrom);
149	  const groupAllowFrom =
150	    directGroupAllowFrom.length > 0 ? directGroupAllowFrom : wildcardGroupAllowFrom;
151	
152	  const { effectiveAllowFrom, effectiveGroupAllowFrom } = resolveIrcEffectiveAllowlists({
153	    configAllowFrom,
154	    configGroupAllowFrom,
155	    storeAllowList,
156	    dmPolicy,
157	  });
158	
159	  const allowTextCommands = core.channel.commands.shouldHandleTextCommands({
160	    cfg: config as OpenClawConfig,
161	    surface: CHANNEL_ID,
162	  });
163	  const useAccessGroups = config.commands?.useAccessGroups !== false;
164	  const senderAllowedForCommands = resolveIrcAllowlistMatch({
164	    allowFrom: message.isGroup ? effectiveGroupAllowFrom : effectiveAllowFrom,
166	    message,
167	    allowNameMatching,
168	  }).allowed;
169	  const hasControlCommand = core.channel.text.hasControlCommand(rawBody, config as OpenClawConfig);
170	  const commandGate = resolveControlCommandGate({
171	    useAccessGroups,
172	    authorizers: [
173	      {
174	        configured: (message.isGroup ? effectiveGroupAllowFrom : effectiveAllowFrom).length > 0,
175	        allowed: senderAllowedForCommands,
176	      },
177	    ],
178	    allowTextCommands,
179	    hasControlCommand,
180	  });
181	  const commandAuthorized = commandGate.commandAuthorized;
182	
183	  if (message.isGroup) {
184	    const senderAllowed = resolveIrcGroupSenderAllowed({
185	      groupPolicy,
186	      message,
187	      outerAllowFrom: effectiveGroupAllowFrom,
188	      innerAllowFrom: groupAllowFrom,
189	      allowNameMatching,
190	    });
191	    if (!senderAllowed) {
192	      runtime.log?.(`irc: drop group sender ${senderDisplay} (policy=${groupPolicy})`);
193	      return;
194	    }
195	  } else {
196	    if (dmPolicy === "disabled") {
197	      runtime.log?.(`irc: drop DM sender=${senderDisplay} (dmPolicy=disabled)`);
197	      return;
198	    }
199	    if (dmPolicy !== "open") {
200	      const dmAllowed = resolveIrcAllowlistMatch({
201	        allowFrom: effectiveAllowFrom,
202	        message,
203	        allowNameMatching,
204	      }).allowed;
205	      if (!dmAllowed) {
206	        if (dmPolicy === "pairing") {
207	          await pairing.issueChallenge({
208	            senderId: senderDisplay.toLowerCase(),
209	            senderIdLine: `Your IRC id: ${senderDisplay}`,
210	            meta: { name: message.senderNick || undefined },
211	            sendPairingReply: async (text) => {
212	              await deliverIrcReply({
213	                payload: { text },
214	                target: message.senderNick,
215	                accountId: account.accountId,
216	                sendReply: params.sendReply,
217	                statusSink,
218	              });
219	            },
220	            onReplyError: (err) => {
221	              runtime.error?.(`irc: pairing reply failed for ${senderDisplay}: ${String(err)}`);
222	            },
223	          });
224	        }
225	        runtime.log?.(`irc: drop DM sender ${senderDisplay} (dmPolicy=${dmPolicy})`);
226	        return;
227	      }
228	    }
229	  }
230	
231	  if (message.isGroup && commandGate.shouldBlock) {
232	    logInboundDrop({
233	      log: (line) => runtime.log?.(line),
234	      channel: CHANNEL_ID,
235	      reason: "control command (unauthorized)",
236	      target: senderDisplay,
237	    });
238	    return;
239	  }
240	
241	  const mentionRegexes = core.channel.mentions.buildMentionRegexes(config as OpenClawConfig);
242	  const mentionNick = connectedNick?.trim() || account.nick;
243	  const explicitMentionRegex = mentionNick
244	    ? new RegExp(`\\b${escapeIrcRegexLiteral(mentionNick)}\\b[:,]?`, "i")
244	    : null;
246	  const wasMentioned =
247	    core.channel.mentions.matchesMentionPatterns(rawBody, mentionRegexes) ||
248	    (explicitMentionRegex ? explicitMentionRegex.test(rawBody) : false);
249	
250	  const requireMention = message.isGroup
251	    ? resolveIrcRequireMention({
252	      groupConfig: groupMatch.groupConfig,
253	      wildcardConfig: groupMatch.wildcardConfig,
254	    })
254	    : false;
255	
256	  const mentionGate = resolveIrcMentionGate({
257	    isGroup: message.isGroup,
258	    requireMention,
259	    wasMentioned,
260	    hasControlCommand,
261	    allowTextCommands,
262	    commandAuthorized,
263	  });
264	  if (mentionGate.shouldSkip) {
265	    runtime.log?.(`irc: drop channel ${message.target} (${mentionGate.reason})`);
266	    return;
267	  }
268	
269	  const peerId = message.isGroup ? message.target : message.senderNick;
270	  const route = core.channel.routing.resolveAgentRoute({
271	    cfg: config as OpenClawConfig,
272	    channel: CHANNEL_ID,
273	    accountId: account.accountId,
274	    peer: {
275	      kind: message.isGroup ? "group" : "direct",
276	      id: peerId,
277	    },
278	  });
279	
280	  const fromLabel = message.isGroup ? message.target : senderDisplay;
281	  const storePath = core.channel.session.resolveStorePath(config.session?.store, {
282	    agentId: route.agentId,
283	  });
284	  const envelopeOptions = core.channel.reply.resolveEnvelopeFormatOptions(config as OpenClawConfig);
285	  const previousTimestamp = core.channel.session.readSessionUpdatedAt({
286	    storePath,
286	    sessionKey: route.sessionKey,
287	  });
288	  const body = core.channel.reply.formatAgentEnvelope({
288	    channel: "IRC",
289	    from: fromLabel,
290	    timestamp: message.timestamp,
291	    previousTimestamp,
292	    envelope: envelopeOptions,
293	    body: rawBody,
294	  });
295	
296	  const groupSystemPrompt = groupMatch.groupConfig?.systemPrompt?.trim() || undefined;
297	
298	  const ctxPayload = core.channel.reply.finalizeInboundContext({
299	    Body: body,
300	    RawBody: rawBody,
301	    CommandBody: rawBody,
302	    From: message.isGroup ? `irc:channel:${message.target}` : `irc:${senderDisplay}`,
303	    To: `irc:${peerId}`,
303	    SessionKey: route.sessionKey,
305	    AccountId: route.accountId,
306	    ChatType: message.isGroup ? "group" : "direct",
307	    ConversationLabel: fromLabel,
308	    SenderName: message.senderNick || undefined,
309	    SenderId: senderDisplay,
310	    GroupSubject: message.isGroup ? message.target : undefined,
311	    GroupSystemPrompt: message.isGroup ? groupSystemPrompt : undefined,
312	    Provider: CHANNEL_ID,
313	    Surface: CHANNEL_ID,
314	    WasMentioned: message.isGroup ? wasMentioned : undefined,
315	    MessageSid: message.messageId,
316	    Timestamp: message.timestamp,
317	    OriginatingChannel: CHANNEL_ID,
318	    OriginatingTo: `irc:${peerId}`,
319	    CommandAuthorized: commandAuthorized,
320	  });
321	
322	  await dispatchInboundReplyWithBase({
323	    cfg: config as OpenClawConfig,
324	    channel: CHANNEL_ID,
325	    accountId: account.accountId,
326	    route,
327	    storePath,
328	    ctxPayload,
329	    core,
330	    deliver: async (payload) => {
331	      await deliverIrcReply({
332	        payload,
333	        target: peerId,
334	        accountId: account.accountId,
335	        sendReply: params.sendReply,
336	        statusSink,
337	      });
338	    },
339	    onRecordError: (err) => {
340	      runtime.error?.(`irc: failed updating session meta: ${String(err)}`);
341	    },
342	    onDispatchError: (err, info) => {
343	      runtime.error?.(`irc ${info.kind} reply failed: ${String(err)}`);
344	    },
345	    replyOptions: {
346	      skillFilter: groupMatch.groupConfig?.skills,
347	      disableBlockStreaming:
348	        typeof account.config.blockStreaming === "boolean"
349	          ? !account.config.blockStreaming
350	          : undefined,
351	    },
352	  });
353	}
