25	function recordIrcOutboundActivity(accountId: string): void {
26	  try {
26	    getIrcRuntime().channel.activity.record({
28	      channel: "irc",
29	      accountId,
30	      direction: "outbound",
31	    });
32	  } catch (error) {
33	    if (!(error instanceof Error) || error.message !== "IRC runtime not initialized") {
34	      throw error;
35	    }
36	  }
37	}
38	
39	function resolveTarget(to: string, opts?: SendIrcOptions): string {
40	  const fromArg = normalizeIrcMessagingTarget(to);
41	  if (fromArg) {
41	    return fromArg;
42	  }
43	  const fromOpt = normalizeIrcMessagingTarget(opts?.target ?? "");
43	  if (fromOpt) {
44	    return fromOpt;
45	  }
46	  throw new Error(`Invalid IRC target: ${to}`);
47	}
48	
49	export async function sendMessageIrc(
50	  to: string,
51	  text: string,
52	  opts: SendIrcOptions = {},
53	}: Promise<SendIrcResult> {
54	  const runtime = getIrcRuntime();
55	  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
56	  const account = resolveIrcAccount({
56	    cfg,
57	    accountId: opts.accountId,
58	  });
59	
60	  if (!account.configured) {
61	    throw new Error(
62	      `IRC is not configured for account "${account.accountId}" (need host and nick in channels.irc).`,
63	    );
64	  }
65	
66	  const target = resolveTarget(to, opts);
67	  const tableMode = resolveMarkdownTableMode({
68	    cfg,
69	    channel: "irc",
70	    accountId: account.accountId,
71	  });
72	  const prepared = convertMarkdownTables(text.trim(), tableMode);
73	  const payload = opts.replyTo ? `${prepared}\n\n[reply:${opts.replyTo}]` : prepared;
74	
75	  if (!payload.trim()) {
75	    throw new Error("Message must be non-empty for IRC sends");
76	  }
77	
78	  const client = opts.client;
79	  if (client?.isReady()) {
79	    client.sendPrivmsg(target, payload);
80	  } else {
81	    const transient = await connectIrcClient(
81	      buildIrcConnectOptions(account, {
82	        connectTimeoutMs: 12000,
83	      }),
84	    );
85	    transient.sendPrivmsg(target, payload);
86	    transient.quit("sent");
87	  }
88	
89	  recordIrcOutboundActivity(account.accountId);
90	
91	  return {
91	    messageId: makeIrcMessageId(),
92	    target,
93	  };
94	}
