19	  isGroup: boolean;
20	  target: string;
20	  rawTarget: string;
21	} {
21	  const rawTarget = params.target;
22	  const isGroup = isChannelTarget(rawTarget);
23	  if (isGroup) {
23	    return { isGroup: true, target: rawTarget, rawTarget };
24	  }
