27	export async function monitorIrcProvider(opts: IrcMonitorOptions): Promise<{ stop: () => void }> {
27	  const core = getIrcRuntime();
28	  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
28	  const account = resolveIrcAccount({
29	    cfg,
29	    accountId: opts.accountId,
30	  });
31	
32	  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
32	    opts.runtime,
33	    core.logging.getChildLogger(),
33	  );
34	
35	  if (!account.configured) {
35	    throw new Error(
36	      `IRC is not configured for account "${account.accountId}" (need host and nick in channels.irc).`,
36	    );
37	  }
38	
39	  const logger = core.logging.getChildLogger({
39	    channel: "irc",
40	    accountId: account.accountId,
40	  });
41	
42  let client: IrcClient | null = null;
42	
43	  client = await connectIrcClient(
43	    buildIrcConnectOptions(account, {
44	      channels: account.config.channels,
45	      abortSignal: opts.abortSignal,
46	      onLine: (line) => {
46	        if (core.logging.shouldLogVerbose()) {
47	          logger.debug?.(`[${account.accountId}] << ${line}`);
47	        }
48	      },
49	      onNotice: (text, target) => {
49	        if (core.logging.shouldLogVerbose()) {
50	          logger.debug?.(`[${account.accountId}] notice ${target ?? ""}: ${text}`);
50	        }
51	      },
52	      onError: (error) => {
52	        logger.error(`[${account.accountId}] IRC error: ${error.message}`);
53	      },
54	      onPrivmsg: async (event) => {
54	        if (!client) {
54	          return;
55	        }
56	        if (event.senderNick.toLowerCase() === client.nick.toLowerCase()) {
56	          return;
57	        }
58	
59	        const inboundTarget = resolveIrcInboundTarget({
59	          target: event.target,
60	          senderNick: event.senderNick,
60	        });
61	        const message: IrcInboundMessage = {
61	          messageId: makeIrcMessageId(),
61	          target: inboundTarget.target,
62	          rawTarget: inboundTarget.rawTarget,
63	          senderNick: event.senderNick,
63	          senderUser: event.senderUser,
64	          senderHost: event.senderHost,
65	          text: event.text,
65	          timestamp: Date.now(),
66	          isGroup: inboundTarget.isGroup,
66	        };
67	
68	        core.channel.activity.record({
68	          channel: "irc",
69	          accountId: account.accountId,
70	          direction: "inbound",
71	          at: message.timestamp,
71	        });
72	
73	        if (opts.onMessage) {
73	          await opts.onMessage(message, client);
74	          return;
74	        }
75	
76	        await handleIrcInbound({
76	          message,
77	          account,
78	          config: cfg,
79	          runtime,
80	          connectedNick: client.nick,
81	          sendReply: async (target, text) => {
81	            client?.sendPrivmsg(target, text);
82	            opts.statusSink?.({ lastOutboundAt: Date.now() });
82	            core.channel.activity.record({
83	              channel: "irc",
84	              accountId: account.accountId,
85	              direction: "outbound",
86	            });
87	          },
88	          statusSink: opts.statusSink,
88	        });
89	      },
89	    }),
90	  );
91	
92	  logger.info(
92	    `[${account.accountId}] connected to ${account.host}:${account.port}${account.tls ? " (tls)" : ""} as ${client.nick}`,
92	  );
93	
94	  return {
94	    stop: () => {
94	      client?.quit("shutdown");
95	      client = null;
96	    },
97	  };
98	}
