38	export function chunkTextForOutbound(text: string, limit: number): string[] {
39	  const chunks: string[] = [];
40	  let remaining = text;
41	  while (remaining.length > limit) {
42	    const window = remaining.slice(0, limit);
43	    const splitAt = Math.max(window.lastIndexOf("\n"), window.lastIndexOf(" "));
44	    const breakAt = splitAt > 0 ? splitAt : limit;
45	    chunks.push(remaining.slice(0, breakAt).trimEnd());
46	    remaining = remaining.slice(breakAt).trimStart();
47	  }
48	  if (remaining.length > 0 || text.length === 0) {
49	    chunks.push(remaining);
50	  }
51	  return chunks;
52	}
