276	/** Detect numeric-looking target ids for channels that distinguish ids from handles. */
277	export function isNumericTargetId(raw: string): boolean {
278	  const trimmed = raw.trim();
279	  if (!trimmed) {
280	    return false;
281	  }
282	  return /^\d{3,}$/.test(trimmed);
283	}
