306	/** Send a caption with only the first media item, mirroring caption-limited channel transports. */
307	export async function sendMediaWithLeadingCaption(params: {
308	  mediaUrls: string[];
309	  caption: string;
310	  send: (payload: { mediaUrl: string; caption?: string }) => Promise<void>;
311	  onError?: (params: {
312	    error: unknown;
313	    mediaUrl: string;
314	    caption?: string;
315	    index: number;
316	    isFirst: boolean;
317	  }) => Promise<void> | void;
318	}): Promise<boolean> {
319	  if (params.mediaUrls.length === 0) {
320	    return false;
321	  }
322	
323	  for (const [index, mediaUrl] of params.mediaUrls.entries()) {
324	    const isFirst = index === 0;
325	    const caption = isFirst ? params.caption : undefined;
326	    try {
327	      await params.send({ mediaUrl, caption });
328	    } catch (error) {
329	      if (params.onError) {
330	        await params.onError({
331	          error,
332	          mediaUrl,
333	          caption,
334	          index,
335	          isFirst,
336	        });
337	        continue;
338	      }
339	      throw error;
340	    }
341	  }
342	  return true;
343	}
344	
345	export async function deliverTextOrMediaReply(params: {
346	  payload: OutboundReplyPayload;
347	  text: string;
348	  chunkText?: (text: string) => readonly string[];
349	  sendText: (text: string) => Promise<void>;
350	  sendMedia: (payload: { mediaUrl: string; caption?: string }) => Promise<void>;
351	  onMediaError?: (params: {
352	    error: unknown;
353	    mediaUrl: string;
354	    caption?: string;
355	    index: number;
356	    isFirst: boolean;
357	  }) => Promise<void> | void;
358	}): Promise<"empty" | "text" | "media"> {
359	  const { mediaUrls } = resolveSendableOutboundReplyParts(params.payload, {
360	    text: params.text,
361	  });
362	  const sentMedia = await sendMediaWithLeadingCaption({
363	    mediaUrls,
364	    caption: params.text,
365	    send: params.sendMedia,
366	    onError: params.onMediaError,
367	  });
368	  if (sentMedia) {
369	    return "media";
370	  }
371	  if (!params.text) {
372	    return "empty";
373	  }
374	  const chunks = params.chunkText ? params.chunkText(params.text) : [params.text];
375	  let sentText = false;
376	  for (const chunk of chunks) {
377	    if (!chunk) {
378	      continue;
379	    }
380	    await params.sendText(chunk);
381	    sentText = true;
382	  }
383	  return sentText ? "text" : "empty";
384	}
