/**
 * Target and allowlist normalization for the PulseBoard channel plugin.
 *
 * PulseBoard addressing:
 *   - Boards:   "#board-name"  (group chat; must start with #)
 *   - DMs:      "username"     (no prefix; @ prefix is stripped on input)
 */

/** Returns true when the target refers to a board (group chat). */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Normalizes a raw PulseBoard target string.
 *
 * Accepted input forms:
 *   - "#board-name", "pulseboard:#board-name", "board:#board-name"
 *   - "username", "@username", "pulseboard:username", "user:username"
 *
 * Returns the canonical form ("#board-name" or "username") or undefined
 * if the input is invalid/empty.
 */
export function normalizePulseBoardTarget(raw: string): string | undefined {
  if (!raw?.trim()) {
    return undefined;
  }

  let value = raw.trim();

  // Strip known prefix forms
  const prefixPatterns = [
    /^pulseboard:board:/i,
    /^pulseboard:/i,
    /^board:/i,
    /^user:/i,
  ];
  for (const pattern of prefixPatterns) {
    if (pattern.test(value)) {
      value = value.replace(pattern, "");
      break;
    }
  }

  value = value.trim();
  if (!value) {
    return undefined;
  }

  // Boards keep their # prefix; strip @ from usernames
  if (value.startsWith("#")) {
    const board = value.toLowerCase();
    // Must have at least one character after #
    if (board.length < 2) {
      return undefined;
    }
    return board;
  }

  // Strip leading @ for usernames
  if (value.startsWith("@")) {
    value = value.slice(1);
  }

  // Usernames must be non-empty, alphanumeric + _ + - only
  const username = value.toLowerCase();
  if (!username || !/^[\w-]+$/.test(username)) {
    return undefined;
  }
  return username;
}

/**
 * Quick heuristic used by targetResolver.looksLikeId: returns true for any
 * string that could be a valid PulseBoard board name or username.
 */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  return normalizePulseBoardTarget(raw) !== undefined;
}

/**
 * Normalizes a single allowlist entry (username or wildcard).
 * Returns null for entries that cannot be normalized.
 */
export function normalizePulseBoardAllowEntry(
  entry: string | number,
): string | null {
  if (typeof entry === "number") {
    return String(entry);
  }
  const trimmed = entry.trim();
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  // Strip @ prefix for usernames
  const username = trimmed.startsWith("@") ? trimmed.slice(1) : trimmed;
  if (!username || !/^[\w-]+$/.test(username)) {
    return null;
  }
  return username.toLowerCase();
}

/**
 * Normalizes an array of raw allowlist entries, dropping invalid ones.
 */
export function normalizePulseBoardAllowlist(
  entries?: Array<string | number>,
): string[] {
  if (!entries?.length) {
    return [];
  }
  const result: string[] = [];
  for (const entry of entries) {
    const normalized = normalizePulseBoardAllowEntry(entry);
    if (normalized) {
      result.push(normalized);
    }
  }
  return result;
}

/**
 * Returns true when `senderUsername` is permitted by the given allowlist.
 * A wildcard entry "*" allows all senders.
 */
export function matchesPulseBoardAllowlist(
  senderUsername: string,
  allowFrom: string[],
): boolean {
  if (!allowFrom.length) {
    return false;
  }
  const normalized = senderUsername.toLowerCase();
  return allowFrom.some((entry) => entry === "*" || entry === normalized);
}

