/**
 * Stub PulseBoard HTTP client.
 *
 * PulseBoard is a fictional platform; this client simulates the transport
 * layer (long-polling / send) without making real network calls. It is
 * designed to be realistic enough that monitor.ts and send.ts can use it
 * as-is, while remaining safe to run in tests without network access.
 */

const DEFAULT_API_URL = "https://api.pulseboard.example";

export type PulseBoardRawMessage = {
  id: string;
  /** Set for board messages; undefined for direct messages. */
  boardName?: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isDirect: boolean;
};

export type PulseBoardClientOptions = {
  apiToken: string;
  apiUrl?: string;
  /** Board names to subscribe to. */
  boards?: string[];
  abortSignal?: AbortSignal;
  onMessage?: (msg: PulseBoardRawMessage) => void | Promise<void>;
};

export type PulseBoardClient = {
  isReady(): boolean;
  sendMessage(to: string, text: string): Promise<{ messageId: string }>;
  disconnect(): void;
};

function makeMessageId(): string {
  return `pb-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

/**
 * Connects to the PulseBoard API and returns a client instance.
 *
 * The stub implementation does not open real network connections. It marks
 * itself as ready immediately and provides no-op send / polling behaviour,
 * suitable for testing and demonstration purposes.
 */
export async function connectPulseBoardClient(
  opts: PulseBoardClientOptions,
): Promise<PulseBoardClient> {
  const { apiToken, apiUrl = DEFAULT_API_URL, boards = [], abortSignal } = opts;

  let ready = true;
  let pollTimer: ReturnType<typeof setInterval> | null = null;

  // Stub long-poll loop — in a real implementation this would call
  // GET /v1/poll with the API token and yield incoming messages.
  // We set up a no-op timer to represent the active connection.
  pollTimer = setInterval(() => {
    if (abortSignal?.aborted) {
      client.disconnect();
    }
  }, 5000);

  abortSignal?.addEventListener("abort", () => {
    client.disconnect();
  });

  const client: PulseBoardClient = {
    isReady() {
      return ready;
    },

    async sendMessage(to: string, text: string): Promise<{ messageId: string }> {
      if (!ready) {
        throw new Error("PulseBoard client is not connected");
      }
      if (!apiToken) {
        throw new Error("PulseBoard: apiToken is required to send messages");
      }
      // Stub: in a real implementation this would POST to
      // `${apiUrl}/v1/messages` with { to, text } and return the message id.
      void apiUrl; // suppress unused variable warning
      void boards; // suppress unused variable warning
      return { messageId: makeMessageId() };
    },

    disconnect() {
      ready = false;
      if (pollTimer !== null) {
        clearInterval(pollTimer);
        pollTimer = null;
      }
    },
  };

  return client;
}

