import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { resolveMergedAccountConfig } from "openclaw/plugin-sdk/account-resolution";
import { tryReadSecretFileSync } from "openclaw/plugin-sdk/core";
import { normalizeResolvedSecretInputString } from "openclaw/plugin-sdk/secret-input";
import type { CoreConfig, PulseBoardAccountConfig } from "./types.js";

export type PulseBoardTokenSource = "env" | "tokenFile" | "config" | "none";

export type ResolvedPulseBoardAccount = {
  accountId: string;
  enabled: boolean;
  name?: string;
  configured: boolean;
  apiToken: string;
  tokenSource: PulseBoardTokenSource;
  config: PulseBoardAccountConfig;
};

export const {
  listAccountIds: listPulseBoardAccountIds,
  resolveDefaultAccountId: resolveDefaultPulseBoardAccountId,
} = createAccountListHelpers("pulseboard", { normalizeAccountId });

function mergePulseBoardAccountConfig(
  cfg: CoreConfig,
  accountId: string,
): PulseBoardAccountConfig {
  return resolveMergedAccountConfig<PulseBoardAccountConfig>({
    channelConfig: cfg.channels?.pulseboard as PulseBoardAccountConfig | undefined,
    accounts: cfg.channels?.pulseboard?.accounts as
      | Record<string, Partial<PulseBoardAccountConfig>>
      | undefined,
    accountId,
    omitKeys: ["defaultAccount"],
    normalizeAccountId,
  });
}

function resolveApiToken(
  accountId: string,
  merged: PulseBoardAccountConfig,
): { apiToken: string; source: PulseBoardTokenSource } {
  // 1. Environment variable (default account only)
  if (accountId === DEFAULT_ACCOUNT_ID) {
    const envToken = process.env.PULSEBOARD_API_TOKEN?.trim();
    if (envToken) {
      return { apiToken: envToken, source: "env" };
    }
  }

  // 2. Token file
  if (merged.tokenFile?.trim()) {
    const fileToken = tryReadSecretFileSync(
      merged.tokenFile,
      "PulseBoard token file",
      { rejectSymlink: true },
    );
    if (fileToken) {
      return { apiToken: fileToken, source: "tokenFile" };
    }
  }

  // 3. Config field
  const configToken = normalizeResolvedSecretInputString({
    value: merged.apiToken,
    path: `channels.pulseboard.accounts.${accountId}.apiToken`,
  });
  if (configToken) {
    return { apiToken: configToken, source: "config" };
  }

  return { apiToken: "", source: "none" };
}

export function resolvePulseBoardAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const hasExplicitAccountId = Boolean(params.accountId?.trim());
  const baseEnabled = params.cfg.channels?.pulseboard?.enabled !== false;

  const resolve = (accountId: string): ResolvedPulseBoardAccount => {
    const merged = mergePulseBoardAccountConfig(params.cfg, accountId);
    const accountEnabled = merged.enabled !== false;
    const enabled = baseEnabled && accountEnabled;

    const { apiToken, source: tokenSource } = resolveApiToken(accountId, merged);

    const config: PulseBoardAccountConfig = {
      ...merged,
    };

    return {
      accountId,
      enabled,
      name: merged.name?.trim() || undefined,
      configured: Boolean(apiToken),
      apiToken,
      tokenSource,
      config,
    };
  };

  const normalized = normalizeAccountId(params.accountId);
  const primary = resolve(normalized);

  if (hasExplicitAccountId) {
    return primary;
  }
  if (primary.configured) {
    return primary;
  }

  // Fall back to the explicitly configured default account if the primary
  // isn't configured (e.g. anonymous default with no token).
  const fallbackId = resolveDefaultPulseBoardAccountId(params.cfg);
  if (fallbackId === primary.accountId) {
    return primary;
  }
  const fallback = resolve(fallbackId);
  if (!fallback.configured) {
    return primary;
  }
  return fallback;
}

export function listEnabledPulseBoardAccounts(
  cfg: CoreConfig,
): ResolvedPulseBoardAccount[] {
  return listPulseBoardAccountIds(cfg)
    .map((accountId) => resolvePulseBoardAccount({ cfg, accountId }))
    .filter((account) => account.enabled);
}

