import { resolvePulseBoardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardProbe } from "./types.js";

const DEFAULT_API_URL = "https://api.pulseboard.example";
const DEFAULT_TIMEOUT_MS = 8000;

/**
 * Probes the PulseBoard API to verify connectivity and token validity.
 *
 * Performs a lightweight GET /v1/ping request with the configured API token
 * and measures round-trip latency. In the stub implementation the fetch
 * always results in a network error (no real server), which is treated as
 * a failed probe rather than a hard error.
 */
export async function probePulseBoard(
  cfg: CoreConfig,
  opts?: { accountId?: string | null; timeoutMs?: number },
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts?.accountId,
  });

  if (!account.configured) {
    return {
      ok: false,
      message: `PulseBoard not configured for account "${account.accountId}" (apiToken is missing).`,
    };
  }

  const apiUrl =
    (cfg.channels?.pulseboard as { apiUrl?: string } | undefined)?.apiUrl ??
    DEFAULT_API_URL;
  const timeoutMs = opts?.timeoutMs ?? DEFAULT_TIMEOUT_MS;
  const start = Date.now();

  try {
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), timeoutMs);

    let response: Response;
    try {
      response = await fetch(`${apiUrl}/v1/ping`, {
        method: "GET",
        headers: {
          Authorization: `Bearer ${account.apiToken}`,
          "Content-Type": "application/json",
        },
        signal: controller.signal,
      });
    } finally {
      clearTimeout(timer);
    }

    const latencyMs = Date.now() - start;

    if (!response.ok) {
      return {
        ok: false,
        message: `PulseBoard API returned HTTP ${response.status} ${response.statusText}`,
        apiUrl,
        latencyMs,
      };
    }

    return {
      ok: true,
      message: "Connected",
      apiUrl,
      latencyMs,
    };
  } catch (err) {
    const latencyMs = Date.now() - start;
    const message =
      err instanceof Error ? err.message : "Unknown error during probe";
    return {
      ok: false,
      message,
      apiUrl,
      latencyMs,
    };
  }
}

