import { resolvePulseBoardAccount } from "./accounts.js";
import { connectPulseBoardClient, type PulseBoardClient } from "./client.js";
import { normalizePulseBoardTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
  /** Reuse an already-connected client instead of opening a transient one. */
  client?: PulseBoardClient;
};

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

function recordPulseBoardOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    // Swallow "runtime not initialized" errors so send works outside the
    // gateway context (e.g. pairing notifications during setup).
    if (
      !(error instanceof Error) ||
      error.message !== "PulseBoard runtime not initialized"
    ) {
      throw error;
    }
  }
}

export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (apiToken is missing).`,
    );
  }

  const target = normalizePulseBoardTarget(to);
  if (!target) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  const payload = opts.replyTo
    ? `${text.trim()}\n\n[reply:${opts.replyTo}]`
    : text.trim();

  if (!payload) {
    throw new Error("PulseBoard: message text must be non-empty");
  }

  let messageId: string;

  if (opts.client?.isReady()) {
    const result = await opts.client.sendMessage(target, payload);
    messageId = result.messageId;
  } else {
    // Open a transient client for fire-and-forget sends (e.g. pairing replies,
    // outbound messages when the monitor is not running).
    const transient = await connectPulseBoardClient({
      apiToken: account.apiToken,
      boards: account.config.boards,
    });
    try {
      const result = await transient.sendMessage(target, payload);
      messageId = result.messageId;
    } finally {
      transient.disconnect();
    }
  }

  recordPulseBoardOutboundActivity(account.accountId);

  return { messageId, target };
}

