import {
  applyAccountNameToChannelSection,
  createSetupInputPresenceValidator,
  normalizeAccountId,
  patchScopedAccountConfig,
  type ChannelSetupInput,
} from "openclaw/plugin-sdk/nextcloud-talk";
import type { CoreConfig, PulseBoardAccountConfig } from "./types.js";

const CHANNEL = "pulseboard" as const;

type PulseBoardSetupInput = ChannelSetupInput & {
  apiToken?: string;
  tokenFile?: string;
  boards?: string[];
};

/** Applies the account name into the top-level pulseboard config section. */
function applyPulseBoardAccountName(params: {
  cfg: CoreConfig;
  accountId: string;
  name: string | undefined;
}): CoreConfig {
  return applyAccountNameToChannelSection({
    cfg: params.cfg,
    channelKey: CHANNEL,
    accountId: params.accountId,
    name: params.name,
  }) as CoreConfig;
}

export function updatePulseBoardAccountConfig(
  cfg: CoreConfig,
  accountId: string,
  patch: Partial<PulseBoardAccountConfig>,
): CoreConfig {
  return patchScopedAccountConfig({
    cfg,
    channelKey: CHANNEL,
    accountId,
    patch,
    ensureChannelEnabled: false,
    ensureAccountEnabled: false,
  }) as CoreConfig;
}

// ChannelSetupAdapter for the PulseBoard channel.
export const pulseBoardSetupAdapter = {
  resolveAccountId: ({ accountId }: { accountId?: string | null }): string =>
    normalizeAccountId(accountId),

  applyAccountName: ({
    cfg,
    accountId,
    name,
  }: {
    cfg: CoreConfig;
    accountId: string;
    name: string | undefined;
  }): CoreConfig => applyPulseBoardAccountName({ cfg, accountId, name }),

  validateInput: createSetupInputPresenceValidator({
    whenNotUseEnv: [
      {
        someOf: ["apiToken", "tokenFile"],
        message:
          "PulseBoard requires an API token (apiToken or tokenFile).",
      },
    ],
  }),

  applyAccountConfig: ({
    cfg,
    accountId,
    input,
  }: {
    cfg: CoreConfig;
    accountId: string;
    input: ChannelSetupInput;
  }): CoreConfig => {
    const setupInput = input as PulseBoardSetupInput;
    const namedCfg = applyPulseBoardAccountName({
      cfg: cfg as CoreConfig,
      accountId,
      name: setupInput.name,
    });

    const patch: Partial<PulseBoardAccountConfig> = {
      enabled: true,
      ...(setupInput.apiToken?.trim()
        ? { apiToken: setupInput.apiToken.trim() }
        : {}),
      ...(setupInput.tokenFile?.trim()
        ? { tokenFile: setupInput.tokenFile.trim() }
        : {}),
      ...(setupInput.boards?.length ? { boards: setupInput.boards } : {}),
    };

    return updatePulseBoardAccountConfig(namedCfg, accountId, patch);
  },
};

