import {
  createTopLevelChannelDmPolicy,
  promptParsedAllowFromForAccount,
  runSingleChannelSecretStep,
  setTopLevelChannelDmPolicyWithAllowFrom,
  type ChannelSetupWizard,
} from "openclaw/plugin-sdk/nextcloud-talk";
import { normalizePulseBoardAllowEntry } from "./normalize.js";
import { pulseBoardSetupAdapter } from "./setup-core.js";

const CHANNEL = "pulseboard" as const;

/**
 * Interactive setup wizard for the PulseBoard channel.
 *
 * Guides the user through:
 *   1. API token input (with env var detection)
 *   2. DM policy selection
 *   3. Allow-from list population
 */
export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel: CHANNEL,

  credentials: [
    {
      inputKey: "apiToken",
      credentialLabel: "PulseBoard API token",
      preferredEnvVar: "PULSEBOARD_API_TOKEN",
      helpTitle: "PulseBoard API token",
      helpLines: [
        "Obtain your API token from the PulseBoard developer portal.",
        "The token authenticates the bot with the PulseBoard server.",
        "",
        "You can also set the PULSEBOARD_API_TOKEN environment variable.",
      ],
