import type { ResolvedPulseBoardAccount } from "./accounts.js";
import {
  matchesPulseBoardAllowlist,
  normalizePulseBoardAllowlist,
} from "./normalize.js";
import {
  GROUP_POLICY_BLOCKED_LABEL,
  createChannelPairingController,
  deliverFormattedTextWithAttachments,
  dispatchInboundReplyWithBase,
  logInboundDrop,
  readStoreAllowFromForDmPolicy,
  resolveAllowlistProviderRuntimeGroupPolicy,
  resolveControlCommandGate,
  resolveDefaultGroupPolicy,
  resolveEffectiveAllowFromLists,
  warnMissingProviderGroupPolicyFallbackOnce,
  type OpenClawConfig,
  type OutboundReplyPayload,
  type RuntimeEnv,
} from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { sendMessagePulseBoard } from "./send.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

const CHANNEL_ID = "pulseboard" as const;

async function deliverPulseBoardReply(params: {
  payload: OutboundReplyPayload;
  target: string;
  accountId: string;
  sendReply?: (target: string, text: string, replyToId?: string) => Promise<void>;
  statusSink?: (patch: { lastOutboundAt?: number }) => void;
}): Promise<void> {
  await deliverFormattedTextWithAttachments({
    payload: params.payload,
    send: async ({ text, replyToId }) => {
      if (params.sendReply) {
        await params.sendReply(params.target, text, replyToId);
      } else {
        await sendMessagePulseBoard(params.target, text, {
          accountId: params.accountId,
          replyTo: replyToId,
        });
      }
      params.statusSink?.({ lastOutboundAt: Date.now() });
    },
  });
}

/**
 * Handles an inbound PulseBoard message.
 *
 * Applies DM/board policy gates (allowlist, pairing), mention gating for
 * boards, then dispatches to the configured agent via dispatchInboundReplyWithBase.
 */
export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  sendReply?: (target: string, text: string, replyToId?: string) => Promise<void>;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<void> {
  const { message, account, config, runtime, statusSink } = params;
  const core = getPulseBoardRuntime();

  const rawBody = message.text?.trim() ?? "";
  if (!rawBody) {
    return;
  }

  statusSink?.({ lastInboundAt: message.timestamp });

  const pairing = createChannelPairingController({
    core,
    channel: CHANNEL_ID,
    accountId: account.accountId,
  });

  const dmPolicy = account.config.dmPolicy ?? "pairing";
  const defaultGroupPolicy = resolveDefaultGroupPolicy(config);
  const { groupPolicy, providerMissingFallbackApplied } =
    resolveAllowlistProviderRuntimeGroupPolicy({
      providerConfigPresent: config.channels?.pulseboard !== undefined,
      groupPolicy: account.config.boardPolicy,
      defaultGroupPolicy,
    });

  if (providerMissingFallbackApplied) {
    warnMissingProviderGroupPolicyFallbackOnce({
      providerKey: CHANNEL_ID,
      accountId: account.accountId,
      blockedLabel: GROUP_POLICY_BLOCKED_LABEL.channel,
      log: (msg) => runtime.log?.(msg),
    });
  }

  // Normalize all allowlists
  const configAllowFrom = normalizePulseBoardAllowlist(account.config.allowFrom);

  // Per-board allow-from (if configured for this specific board)
  const boardCfg = message.isBoard
    ? (account.config.boardConfig?.[message.target] ?? null)
    : null;
  const boardAllowFrom = normalizePulseBoardAllowlist(boardCfg?.allowFrom);

  // Merge pairing store entries
  const storeAllowFrom = await readStoreAllowFromForDmPolicy({
    provider: CHANNEL_ID,
    accountId: account.accountId,
    dmPolicy,
    readStore: pairing.readStoreForDmPolicy,
  });
  const normalizedStoreAllowFrom = normalizePulseBoardAllowlist(storeAllowFrom);

  const { effectiveAllowFrom, effectiveGroupAllowFrom } =
    resolveEffectiveAllowFromLists({
      allowFrom: configAllowFrom,
      groupAllowFrom: normalizePulseBoardAllowlist(
        account.config.boardPolicy ? configAllowFrom : [],
      ),
      storeAllowFrom: normalizedStoreAllowFrom,
      dmPolicy,
      groupAllowFromFallbackToAllowFrom: true,
    });

  // --- Board (group) access gate ---
  if (message.isBoard) {
    const configuredBoards = (account.config.boards ?? []).map((b) =>
      b.toLowerCase(),
    );
    const isKnownBoard =
      configuredBoards.length === 0 ||
      configuredBoards.includes(message.target.toLowerCase());

    if (!isKnownBoard && groupPolicy === "allowlist") {
      runtime.log?.(
        `pulseboard: drop board ${message.target} (not in configured boards list)`,
      );
      return;
    }

    // Sender allowlist gate for boards
    if (groupPolicy === "allowlist") {
      const outerAllowed = matchesPulseBoardAllowlist(
        message.senderUsername,
        effectiveGroupAllowFrom,
      );
      const innerAllowed =
        boardAllowFrom.length > 0
          ? matchesPulseBoardAllowlist(message.senderUsername, boardAllowFrom)
          : true;

      if (!outerAllowed && !innerAllowed) {
        runtime.log?.(
          `pulseboard: drop board sender ${message.senderUsername} in ${message.target} (policy=${groupPolicy})`,
        );
        return;
      }
    } else if (groupPolicy === "disabled") {
      logInboundDrop({
        log: (line) => runtime.log?.(line),
        channel: CHANNEL_ID,
        reason: `boardPolicy=disabled`,
        target: message.target,
      });
      return;
    }
  }

  // --- DM access gate ---
  if (!message.isBoard) {
    if (dmPolicy === "disabled") {
      runtime.log?.(
        `pulseboard: drop DM sender=${message.senderUsername} (dmPolicy=disabled)`,
      );
      return;
    }

    if (dmPolicy !== "open") {
      const dmAllowed = matchesPulseBoardAllowlist(
        message.senderUsername,
        effectiveAllowFrom,
      );

      if (!dmAllowed) {
        if (dmPolicy === "pairing") {
          await pairing.issueChallenge({
            senderId: message.senderUsername.toLowerCase(),
            senderIdLine: `Your PulseBoard username: ${message.senderUsername}`,
            meta: { name: message.senderUsername },
            sendPairingReply: async (text) => {
              await deliverPulseBoardReply({
                payload: { text },
                target: message.senderUsername,
                accountId: account.accountId,
                sendReply: params.sendReply,
                statusSink,
              });
            },
            onReplyError: (err) => {
              runtime.error?.(
                `pulseboard: pairing reply failed for ${message.senderUsername}: ${String(err)}`,
              );
            },
          });
        }
        runtime.log?.(
          `pulseboard: drop DM sender ${message.senderUsername} (dmPolicy=${dmPolicy})`,
        );
        return;
      }
    }
  }

  // --- Control command authorization gate ---
  const allowTextCommands = core.channel.commands.shouldHandleTextCommands({
    cfg: config as OpenClawConfig,
    surface: CHANNEL_ID,
  });
  const senderAllowlist = message.isBoard
    ? effectiveGroupAllowFrom
    : effectiveAllowFrom;
  const senderAllowedForCommands = matchesPulseBoardAllowlist(
    message.senderUsername,
    senderAllowlist,
  );
  const hasControlCommand = core.channel.text.hasControlCommand(
    rawBody,
    config as OpenClawConfig,
  );
  const commandGate = resolveControlCommandGate({
    useAccessGroups: config.commands?.useAccessGroups !== false,
    authorizers: [
      {
        configured: senderAllowlist.length > 0,
        allowed: senderAllowedForCommands,
      },
    ],
    allowTextCommands,
    hasControlCommand,
  });

  if (message.isBoard && commandGate.shouldBlock) {
    logInboundDrop({
      log: (line) => runtime.log?.(line),
      channel: CHANNEL_ID,
      reason: "control command (unauthorized)",
      target: message.senderUsername,
    });
    return;
  }

  // --- Mention gate (boards only) ---
  const mentionRegexes = core.channel.mentions.buildMentionRegexes(
    config as OpenClawConfig,
  );
  const wasMentioned =
    core.channel.mentions.matchesMentionPatterns(rawBody, mentionRegexes) ||
    /@\w/.test(rawBody); // any @-mention counts as a PulseBoard mention

  const requireMention = message.isBoard
    ? (boardCfg?.requireMention ?? true)
    : false;

  if (
    message.isBoard &&
    requireMention &&
    !wasMentioned &&
    !commandGate.commandAuthorized
  ) {
    runtime.log?.(
      `pulseboard: drop board ${message.target} (requireMention=true, not mentioned)`,
    );
    return;
  }

  // --- Route resolution and dispatch ---
  const peerId = message.isBoard ? message.target : message.senderUsername;
  const route = core.channel.routing.resolveAgentRoute({
    cfg: config as OpenClawConfig,
    channel: CHANNEL_ID,
    accountId: account.accountId,
    peer: {
      kind: message.isBoard ? "group" : "direct",
      id: peerId,
    },
  });

  const fromLabel = message.isBoard
    ? message.target
    : message.senderUsername;
  const storePath = core.channel.session.resolveStorePath(
    config.session?.store,
    { agentId: route.agentId },
  );
  const envelopeOptions = core.channel.reply.resolveEnvelopeFormatOptions(
    config as OpenClawConfig,
  );
  const previousTimestamp = core.channel.session.readSessionUpdatedAt({
    storePath,
    sessionKey: route.sessionKey,
  });

  const body = core.channel.reply.formatAgentEnvelope({
    channel: "PulseBoard",
    from: fromLabel,
    timestamp: message.timestamp,
    previousTimestamp,
    envelope: envelopeOptions,
    body: rawBody,
  });

  const boardSystemPrompt = boardCfg?.systemPrompt?.trim() || undefined;

  const ctxPayload = core.channel.reply.finalizeInboundContext({
    Body: body,
    RawBody: rawBody,
    CommandBody: rawBody,
    From: message.isBoard
      ? `pulseboard:board:${message.target}`
      : `pulseboard:${message.senderUsername}`,
    To: `pulseboard:${peerId}`,
    SessionKey: route.sessionKey,
    AccountId: route.accountId,
    ChatType: message.isBoard ? "group" : "direct",
    ConversationLabel: fromLabel,
    SenderName: message.senderUsername,
    SenderId: message.senderUsername,
    GroupSubject: message.isBoard ? message.target : undefined,
    GroupSystemPrompt: message.isBoard ? boardSystemPrompt : undefined,
    Provider: CHANNEL_ID,
    Surface: CHANNEL_ID,
    WasMentioned: message.isBoard ? wasMentioned : undefined,
    MessageSid: message.messageId,
    Timestamp: message.timestamp,
    OriginatingChannel: CHANNEL_ID,
    OriginatingTo: `pulseboard:${peerId}`,
    CommandAuthorized: commandGate.commandAuthorized,
  });

  await dispatchInboundReplyWithBase({
    cfg: config as OpenClawConfig,
    channel: CHANNEL_ID,
    accountId: account.accountId,
    route,
    storePath,
    ctxPayload,
    core,
    deliver: async (payload) => {
      await deliverPulseBoardReply({
        payload,
        target: peerId,
        accountId: account.accountId,
        sendReply: params.sendReply,
        statusSink,
      });
    },
    onRecordError: (err) => {
      runtime.error?.(
        `pulseboard: failed updating session meta: ${String(err)}`,
      );
    },
    onDispatchError: (err, info) => {
      runtime.error?.(`pulseboard ${info.kind} reply failed: ${String(err)}`);
    },
    replyOptions: {
      skillFilter: boardCfg?.systemPrompt ? undefined : undefined,
      disableBlockStreaming:
        typeof account.config.blockStreaming === "boolean"
          ? !account.config.blockStreaming
          : undefined,
    },
  });
}

