    from: fromLabel,
    timestamp: message.timestamp,
    previousTimestamp,
    envelope: envelopeOptions,
    body: rawBody,
  });

  const boardSystemPrompt = boardCfg?.systemPrompt?.trim() || undefined;

  const ctxPayload = core.channel.reply.finalizeInboundContext({
    Body: body,
    RawBody: rawBody,
    CommandBody: rawBody,
    From: message.isBoard
      ? `pulseboard:board:${message.target}`
      : `pulseboard:${message.senderUsername}`,
    To: `pulseboard:${peerId}`,
    SessionKey: route.sessionKey,
    AccountId: route.accountId,
    ChatType: message.isBoard ? "group" : "direct",
    ConversationLabel: fromLabel,
    SenderName: message.senderUsername,
    SenderId: message.senderUsername,
    GroupSubject: message.isBoard ? message.target : undefined,
    GroupSystemPrompt: message.isBoard ? boardSystemPrompt : undefined,
    Provider: CHANNEL_ID,
    Surface: CHANNEL_ID,
    WasMentioned: message.isBoard ? wasMentioned : undefined,
    MessageSid: message.messageId,
    Timestamp: message.timestamp,
    OriginatingChannel: CHANNEL_ID,
    OriginatingTo: `pulseboard:${peerId}`,
    CommandAuthorized: commandGate.commandAuthorized,
  });

  await dispatchInboundReplyWithBase({
    cfg: config as OpenClawConfig,
    channel: CHANNEL_ID,
    accountId: account.accountId,
    route,
    storePath,
    ctxPayload,
    core,
    deliver: async (payload) => {
      await deliverPulseBoardReply({
        payload,
        target: peerId,
        accountId: account.accountId,
        sendReply: params.sendReply,
        statusSink,
      });
    },
    onRecordError: (err) => {
      runtime.error?.(
        `pulseboard: failed updating session meta: ${String(err)}`,
      );
    },
    onDispatchError: (err, info) => {
      runtime.error?.(`pulseboard ${info.kind} reply failed: ${String(err)}`);
    },
    replyOptions: {
      skillFilter: boardCfg?.systemPrompt ? undefined : undefined,
      disableBlockStreaming:
        typeof account.config.blockStreaming === "boolean"
          ? !account.config.blockStreaming
          : undefined,
    },
  });
}

