import { afterEach, beforeEach, describe, expect, it } from "vitest";
import {
  listEnabledPulseBoardAccounts,
  resolvePulseBoardAccount,
} from "./accounts.js";
import type { CoreConfig } from "./types.js";

function makeCfg(
  pulseboard?: Record<string, unknown>,
): CoreConfig {
  return {
    channels: {
      pulseboard: pulseboard as CoreConfig["channels"]["pulseboard"],
    },
  } as CoreConfig;
}

describe("resolvePulseBoardAccount", () => {
  const originalEnv = process.env.PULSEBOARD_API_TOKEN;

  beforeEach(() => {
    delete process.env.PULSEBOARD_API_TOKEN;
  });

  afterEach(() => {
    if (originalEnv !== undefined) {
      process.env.PULSEBOARD_API_TOKEN = originalEnv;
    } else {
      delete process.env.PULSEBOARD_API_TOKEN;
    }
  });

  it("returns configured=false when no token is present", () => {
    const account = resolvePulseBoardAccount({ cfg: makeCfg({}) });
    expect(account.configured).toBe(false);
    expect(account.apiToken).toBe("");
    expect(account.tokenSource).toBe("none");
  });

  it("resolves token from config apiToken field", () => {
    const account = resolvePulseBoardAccount({
      cfg: makeCfg({ apiToken: "tok_test_abc" }),
    });
    expect(account.configured).toBe(true);
    expect(account.apiToken).toBe("tok_test_abc");
    expect(account.tokenSource).toBe("config");
  });

  it("prefers PULSEBOARD_API_TOKEN env var over config for default account", () => {
    process.env.PULSEBOARD_API_TOKEN = "tok_env_xyz";
    const account = resolvePulseBoardAccount({
      cfg: makeCfg({ apiToken: "tok_config_abc" }),
    });
    expect(account.apiToken).toBe("tok_env_xyz");
    expect(account.tokenSource).toBe("env");
  });

  it("does not use env var for named (non-default) accounts", () => {
    process.env.PULSEBOARD_API_TOKEN = "tok_env_xyz";
    const account = resolvePulseBoardAccount({
      cfg: makeCfg({
        accounts: {
          secondary: { apiToken: "tok_secondary" },
        },
      }),
      accountId: "secondary",
    });
    expect(account.apiToken).toBe("tok_secondary");
    expect(account.tokenSource).toBe("config");
  });

  it("respects enabled=false at account level", () => {
    const account = resolvePulseBoardAccount({
      cfg: makeCfg({ apiToken: "tok_test", enabled: false }),
    });
    expect(account.enabled).toBe(false);
  });

  it("resolves accountId defaults to 'default'", () => {
    const account = resolvePulseBoardAccount({
      cfg: makeCfg({ apiToken: "tok" }),
    });
    expect(account.accountId).toBe("default");
  });

  it("returns correct config reference", () => {
    const cfg = makeCfg({ apiToken: "tok", boards: ["#dev"] });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.config.boards).toEqual(["#dev"]);
  });
});

describe("listEnabledPulseBoardAccounts", () => {
  it("returns empty list when pulseboard not configured", () => {
    const accounts = listEnabledPulseBoardAccounts({} as CoreConfig);
    expect(accounts).toHaveLength(0);
  });

  it("returns default account when configured and enabled", () => {
    const accounts = listEnabledPulseBoardAccounts(
      makeCfg({ apiToken: "tok" }),
    );
    expect(accounts).toHaveLength(1);
    expect(accounts[0].accountId).toBe("default");
  });

  it("excludes disabled accounts", () => {
    const accounts = listEnabledPulseBoardAccounts(
      makeCfg({ apiToken: "tok", enabled: false }),
    );
    expect(accounts).toHaveLength(0);
  });
});

