import { beforeEach, describe, expect, it, vi } from "vitest";
import type { PulseBoardClient } from "./client.js";
import { sendMessagePulseBoard } from "./send.js";
import type { CoreConfig } from "./types.js";

// Mock the runtime so send.ts doesn't crash without a gateway
vi.mock("./runtime.js", () => ({
  getPulseBoardRuntime: () => ({
    config: {
      loadConfig: () =>
        ({
          channels: { pulseboard: { apiToken: "tok_default" } },
        }) as CoreConfig,
    },
    channel: {
      activity: { record: vi.fn() },
    },
  }),
}));

function makeClient(overrides?: Partial<PulseBoardClient>): PulseBoardClient {
  return {
    isReady: () => true,
    sendMessage: vi.fn().mockResolvedValue({ messageId: "msg-123" }),
    disconnect: vi.fn(),
    ...overrides,
  };
}

describe("sendMessagePulseBoard", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("sends to a board target and returns messageId + target", async () => {
    const client = makeClient();
    const result = await sendMessagePulseBoard("#general", "hello world", {
      cfg: { channels: { pulseboard: { apiToken: "tok" } } } as CoreConfig,
      client,
    });
    expect(result.target).toBe("#general");
    expect(result.messageId).toBe("msg-123");
    expect(client.sendMessage).toHaveBeenCalledWith("#general", "hello world");
  });

  it("sends to a DM target", async () => {
    const client = makeClient();
    const result = await sendMessagePulseBoard("alice", "hi alice", {
      cfg: { channels: { pulseboard: { apiToken: "tok" } } } as CoreConfig,
      client,
    });
    expect(result.target).toBe("alice");
    expect(client.sendMessage).toHaveBeenCalledWith("alice", "hi alice");
  });

  it("strips @ prefix from DM targets", async () => {
    const client = makeClient();
    const result = await sendMessagePulseBoard("@bob", "hey", {
      cfg: { channels: { pulseboard: { apiToken: "tok" } } } as CoreConfig,
      client,
    });
    expect(result.target).toBe("bob");
  });

  it("appends reply suffix when replyTo is set", async () => {
    const client = makeClient();
    await sendMessagePulseBoard("alice", "my reply", {
      cfg: { channels: { pulseboard: { apiToken: "tok" } } } as CoreConfig,
      client,
      replyTo: "msg-999",
    });
    expect(client.sendMessage).toHaveBeenCalledWith(
      "alice",
      "my reply\n\n[reply:msg-999]",
    );
  });

  it("throws for an invalid target", async () => {
    await expect(
      sendMessagePulseBoard("", "text", {
        cfg: { channels: { pulseboard: { apiToken: "tok" } } } as CoreConfig,
        client: makeClient(),
      }),
    ).rejects.toThrow("Invalid PulseBoard target");
  });

  it("throws when account is not configured (no token)", async () => {
    await expect(
      sendMessagePulseBoard("alice", "text", {
        cfg: { channels: { pulseboard: {} } } as CoreConfig,
        client: makeClient(),
      }),
    ).rejects.toThrow("not configured");
  });

  it("opens a transient client when provided client is not ready", async () => {
    // Client says not ready — send.ts should fall back to connectPulseBoardClient.
    // We just assert it doesn't call sendMessage on the notReady client and
    // completes without error (the stub connectPulseBoardClient always succeeds).
    const notReadyClient = makeClient({ isReady: () => false });
    await sendMessagePulseBoard("#dev", "fallback send", {
      cfg: { channels: { pulseboard: { apiToken: "tok" } } } as CoreConfig,
      client: notReadyClient,
    });
    expect(notReadyClient.sendMessage).not.toHaveBeenCalled();
  });
});

