import { beforeEach, describe, expect, it, vi } from "vitest";
import type { ResolvedPulseBoardAccount } from "./accounts.js";
import { handlePulseBoardInbound } from "./inbound.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

// ---- Shared test doubles ----

function makeAccount(
  overrides?: Partial<ResolvedPulseBoardAccount>,
): ResolvedPulseBoardAccount {
  return {
    accountId: "default",
    enabled: true,
    configured: true,
    apiToken: "tok_test",
    tokenSource: "config",
    config: {
      dmPolicy: "allowlist",
      allowFrom: ["alice"],
      boardPolicy: "allowlist",
      boards: ["#general"],
      boardConfig: {
        "#general": { requireMention: false },
      },
    },
    ...overrides,
  };
}

function makeCfg(extra?: Partial<CoreConfig>): CoreConfig {
  return {
    channels: { pulseboard: { apiToken: "tok_test" } },
    ...extra,
  } as CoreConfig;
}

function makeBoardMessage(
  overrides?: Partial<PulseBoardInboundMessage>,
): PulseBoardInboundMessage {
  return {
    messageId: "msg-1",
    target: "#general",
    senderUsername: "alice",
    text: "hello board",
    timestamp: Date.now(),
    isBoard: true,
    ...overrides,
  };
}

function makeDmMessage(
  overrides?: Partial<PulseBoardInboundMessage>,
): PulseBoardInboundMessage {
  return {
    messageId: "msg-2",
    target: "alice",
    senderUsername: "alice",
    text: "hello dm",
    timestamp: Date.now(),
    isBoard: false,
    ...overrides,
  };
}

// ---- Core runtime mock ----

const mockDispatch = vi.fn();
const mockIssueChallenge = vi.fn();

vi.mock("./runtime.js", () => ({
  getPulseBoardRuntime: () => ({
    config: { loadConfig: () => ({}) },
    channel: {
      commands: { shouldHandleTextCommands: () => false },
      text: { hasControlCommand: () => false },
      mentions: {
        buildMentionRegexes: () => [],
        matchesMentionPatterns: () => false,
      },
      routing: {
        resolveAgentRoute: () => ({
          agentId: "agent-1",
          accountId: "default",
          sessionKey: "sess-key",
        }),
      },
      session: {
        resolveStorePath: () => "/tmp/session",
        readSessionUpdatedAt: () => null,
      },
      reply: {
        resolveEnvelopeFormatOptions: () => ({}),
        formatAgentEnvelope: ({ body }: { body: string }) => body,
        finalizeInboundContext: (ctx: unknown) => ctx,
      },
      activity: { record: vi.fn() },
    },
    logging: {
      getChildLogger: () => ({
        info: vi.fn(),
        error: vi.fn(),
        debug: vi.fn(),
      }),
    },
  }),
}));

vi.mock("openclaw/plugin-sdk/nextcloud-talk", async (importOriginal) => {
  const mod = await importOriginal<typeof import("openclaw/plugin-sdk/nextcloud-talk")>();
  return {
    ...mod,
    dispatchInboundReplyWithBase: mockDispatch,
    createChannelPairingController: () => ({
      readStoreForDmPolicy: vi.fn().mockResolvedValue([]),
      issueChallenge: mockIssueChallenge,
    }),
    readStoreAllowFromForDmPolicy: vi.fn().mockResolvedValue([]),
    resolveAllowlistProviderRuntimeGroupPolicy: vi.fn().mockReturnValue({
      groupPolicy: "allowlist",
      providerMissingFallbackApplied: false,
    }),
    resolveDefaultGroupPolicy: vi.fn().mockReturnValue("allowlist"),
    resolveEffectiveAllowFromLists: vi.fn().mockImplementation(
      ({ allowFrom, groupAllowFrom }: { allowFrom: string[]; groupAllowFrom: string[] }) => ({
        effectiveAllowFrom: allowFrom,
        effectiveGroupAllowFrom: groupAllowFrom,
      }),
    ),
  };
});

vi.mock("openclaw/plugin-sdk/irc", async (importOriginal) => {
  const mod = await importOriginal<typeof import("openclaw/plugin-sdk/irc")>();
  return {
    ...mod,
    resolveEffectiveAllowFromLists: vi.fn().mockImplementation(
      ({ allowFrom, groupAllowFrom }: { allowFrom: string[]; groupAllowFrom: string[] }) => ({
        effectiveAllowFrom: allowFrom,
        effectiveGroupAllowFrom: groupAllowFrom ?? allowFrom,
      }),
    ),
    resolveControlCommandGate: vi.fn().mockReturnValue({
      commandAuthorized: false,
      shouldBlock: false,
    }),
  };
});

const mockRuntime = {
  log: vi.fn(),
  error: vi.fn(),
};

describe("handlePulseBoardInbound", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockDispatch.mockResolvedValue(undefined);
    mockIssueChallenge.mockResolvedValue(undefined);
  });

  describe("DM messages", () => {
    it("dispatches when sender is on the DM allowlist", async () => {
      await handlePulseBoardInbound({
        message: makeDmMessage({ senderUsername: "alice" }),
        account: makeAccount(),
        config: makeCfg(),
        runtime: mockRuntime,
      });
      expect(mockDispatch).toHaveBeenCalledTimes(1);
    });

    it("drops DM when sender is NOT on the allowlist (dmPolicy=allowlist)", async () => {
      await handlePulseBoardInbound({
        message: makeDmMessage({ senderUsername: "mallory" }),
        account: makeAccount(),
        config: makeCfg(),
        runtime: mockRuntime,
      });
      expect(mockDispatch).not.toHaveBeenCalled();
    });

    it("drops DM and issues pairing challenge when dmPolicy=pairing and sender unknown", async () => {
      await handlePulseBoardInbound({
