import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

// ---- Shared test doubles ----

function makeAccount(
  overrides?: Partial<ResolvedPulseBoardAccount>,
): ResolvedPulseBoardAccount {
  return {
    accountId: "default",
    enabled: true,
    configured: true,
    apiToken: "tok_test",
    tokenSource: "config",
    config: {
      dmPolicy: "allowlist",
      allowFrom: ["alice"],
      boardPolicy: "allowlist",
      boards: ["#general"],
      boardConfig: {
        "#general": { requireMention: false },
      },
    },
    ...overrides,
  };
}

function makeCfg(extra?: Partial<CoreConfig>): CoreConfig {
  return {
    channels: { pulseboard: { apiToken: "tok_test" } },
    ...extra,
  } as CoreConfig;
}

function makeBoardMessage(
  overrides?: Partial<PulseBoardInboundMessage>,
): PulseBoardInboundMessage {
  return {
    messageId: "msg-1",
    target: "#general",
    senderUsername: "alice",
    text: "hello board",
    timestamp: Date.now(),
    isBoard: true,
    ...overrides,
  };
}

function makeDmMessage(
  overrides?: Partial<PulseBoardInboundMessage>,
): PulseBoardInboundMessage {
  return {
    messageId: "msg-2",
    target: "alice",
    senderUsername: "alice",
    text: "hello dm",
    timestamp: Date.now(),
    isBoard: false,
    ...overrides,
  };
}

// ---- Core runtime mock ----

