    config: { loadConfig: () => ({}) },
    channel: {
      commands: { shouldHandleTextCommands: () => false },
      text: { hasControlCommand: () => false },
      mentions: {
        buildMentionRegexes: () => [],
        matchesMentionPatterns: () => false,
      },
      routing: {
        resolveAgentRoute: () => ({
          agentId: "agent-1",
          accountId: "default",
          sessionKey: "sess-key",
        }),
      },
      session: {
        resolveStorePath: () => "/tmp/session",
        readSessionUpdatedAt: () => null,
      },
      reply: {
        resolveEnvelopeFormatOptions: () => ({}),
        formatAgentEnvelope: ({ body }: { body: string }) => body,
        finalizeInboundContext: (ctx: unknown) => ctx,
      },
      activity: { record: vi.fn() },
    },
    logging: {
      getChildLogger: () => ({
        info: vi.fn(),
        error: vi.fn(),
        debug: vi.fn(),
      }),
    },
  }),
}));

vi.mock("openclaw/plugin-sdk/nextcloud-talk", async (importOriginal) => {
  const mod = await importOriginal<typeof import("openclaw/plugin-sdk/nextcloud-talk")>();
  return {
    ...mod,
    dispatchInboundReplyWithBase: mockDispatch,
    createChannelPairingController: () => ({
      readStoreForDmPolicy: vi.fn().mockResolvedValue([]),
      issueChallenge: mockIssueChallenge,
    }),
    readStoreAllowFromForDmPolicy: vi.fn().mockResolvedValue([]),
    resolveAllowlistProviderRuntimeGroupPolicy: vi.fn().mockReturnValue({
      groupPolicy: "allowlist",
      providerMissingFallbackApplied: false,
    }),
    resolveDefaultGroupPolicy: vi.fn().mockReturnValue("allowlist"),
    resolveEffectiveAllowFromLists: vi.fn().mockImplementation(
      ({ allowFrom, groupAllowFrom }: { allowFrom: string[]; groupAllowFrom: string[] }) => ({
        effectiveAllowFrom: allowFrom,
        effectiveGroupAllowFrom: groupAllowFrom,
      }),
    ),
  };
});

