import { describe, expect, it } from "vitest";

// Lightweight smoke tests for the pulseBoardPlugin shape.
// These verify the static declarations without requiring a full runtime.

// We mock the SDK imports that require a live runtime so the module loads cleanly.
vi.mock("openclaw/plugin-sdk/irc", () => ({
  getChatChannelMeta: (id: string) => ({
    label: id,
    detailLabel: id,
    selectionLabel: id,
  }),
  chunkTextForOutbound: (text: string, _limit: number) => [text],
  PAIRING_APPROVED_MESSAGE: "Your pairing request has been approved.",
  createAccountStatusSink: vi.fn(),
  resolveControlCommandGate: vi.fn(),
  resolveEffectiveAllowFromLists: vi.fn(),
}));

vi.mock("openclaw/plugin-sdk/nextcloud-talk", async (importOriginal) => {
  const mod = await importOriginal<typeof import("openclaw/plugin-sdk/nextcloud-talk")>();
  return {
    ...mod,
    dispatchInboundReplyWithBase: vi.fn(),
    createChannelPairingController: vi.fn(),
    readStoreAllowFromForDmPolicy: vi.fn(),
    resolveAllowlistProviderRuntimeGroupPolicy: vi.fn(),
    resolveDefaultGroupPolicy: vi.fn(),
    resolveEffectiveAllowFromLists: vi.fn(),
  };
});

// Import after mocks are registered
const { pulseBoardPlugin } = await import("./channel.js");

describe("pulseBoardPlugin shape", () => {
  it("has the correct channel id", () => {
    expect(pulseBoardPlugin.id).toBe("pulseboard");
  });

  it("supports both direct and group chat types", () => {
    expect(pulseBoardPlugin.capabilities?.chatTypes).toContain("direct");
    expect(pulseBoardPlugin.capabilities?.chatTypes).toContain("group");
  });

  it("has textChunkLimit of 4000", () => {
    // The chunk limit lives on the outbound adapter's base config.
    // We verify it via the config stored in the plugin's outbound section.
    const outbound = (pulseBoardPlugin as { outbound?: { base?: { textChunkLimit?: number } } })
      .outbound;
    expect(outbound?.base?.textChunkLimit).toBe(4000);
  });

  it("does not advertise media support (stub client)", () => {
    expect(pulseBoardPlugin.capabilities?.media).toBe(false);
  });

  it("advertises blockStreaming=true", () => {
    expect(pulseBoardPlugin.capabilities?.blockStreaming).toBe(true);
  });

  it("has a sendText handler in attachedResults", () => {
    const outbound = (pulseBoardPlugin as { outbound?: { attachedResults?: { sendText?: unknown } } })
      .outbound;
    expect(typeof outbound?.attachedResults?.sendText).toBe("function");
  });

  it("has a pairing.text section with idLabel=pulseboardUser", () => {
    const pairing = (pulseBoardPlugin as { pairing?: { text?: { idLabel?: string } } }).pairing;
    expect(pairing?.text?.idLabel).toBe("pulseboardUser");
  });
});

